class Bad {
    private val name: String = "hello"
    fun bad() {
        val s = name.toString()
    }
}

class Good {
    private val name: String = "hello"
    fun good(): String {
        return name
    }
}

fun good(value: Int): String {
    return value.toString()
}

private fun reportProblem(
    cause: Exception,
    info: String,
    context: String,
    service: Any
) {
    // no-op
}

private data class RequestData(
    val userId: String,
    val cardNumber: String,
    val iban: String
)

private fun reproduceFalsePositive(request: RequestData, service: Any, ex: Exception) {
    reportProblem(
        cause = ex,
        info =
            "userId: ${request.userId} card: " +
                "${request.cardNumber} iban:${request.iban}",
        context = "unlinking".toString(), // violation
        service = service
    )
}

class ServiceException(msg: String, cause: Throwable? = null) : Exception(msg, cause)

fun bad(ioException: java.io.IOException) {
    throw ServiceException(
        "Exception encountered".toString(),
        cause = ioException
    )
}
